using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Look up a configuration value by key.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up (e.g. 'MaxRetries')")] string key)
    {
        var config = AppConfiguration.Current;
        return config.TryGetValue(key, out var value)
            ? $"{key} = {value}"
            : $"Key '{key}' not found. Available keys: {string.Join(", ", config.Keys)}";
    }

    [McpServerTool, Description("Update a configuration value by key.")]
    public static string SetConfigValue(
        [Description("The configuration key to set")] string key,
        [Description("The new value")] string value)
    {
        AppConfiguration.Current[key] = value;
        return $"Updated {key} = {value}";
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the full application configuration as JSON.")]
    public static string GetAllSettings() =>
        JsonSerializer.Serialize(AppConfiguration.Current, AppConfiguration.JsonOptions);

    [McpServerResource(
        UriTemplate = "config://app/info",
        Name = "App Info",
        MimeType = "application/json"),
     Description("Returns server name and version.")]
    public static string GetAppInfo() =>
        JsonSerializer.Serialize(new { Name = "ConfigMcpServer", Version = "1.0.0" });
}

using System.Text.Json;

public static class AppConfiguration
{
    public static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    public static Dictionary<string, string> Current { get; } = new()
    {
        ["MaxRetries"] = "3",
        ["TimeoutSeconds"] = "30",
        ["LogLevel"] = "Information",
        ["FeatureFlags"] = "darkMode=true;betaApi=false"
    };
}

